var e=[{id:`L2_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`으윽...... 으으윽......`,JPN:`ううっ……うううっ……`,ENG:`Ugh... Urrgghhh...`,TWN:`唔……呃呃呃……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`이봐! 괜찮은가?!`,JPN:`おい！　大丈夫か！？`,ENG:`Hey! Are you okay?!`,TWN:`喂！沒事吧？！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`식별코드는...... 정보부 선발대인가 보군.`,JPN:`識別コードは……情報局の選抜隊のようだな。`,ENG:`Your identification code... So, you're in the Intelligence Agency's advance party.`,TWN:`識別代碼是……看來是情報部先頭部隊。`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`상처가 심한데...... 정신이 드나?`,JPN:`ひどいケガだが……気がついたか？`,ENG:`You're badly wounded. Can you talk?`,TWN:`傷得很重啊……還有意識嗎？`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`괴...... 괴물...... 저리가...... 저리가......!!`,JPN:`ば……化け物……あっち行け……近寄るな……！！`,ENG:`M-monster... G-go... Go away... Go!`,TWN:`怪……怪物……別過來……別過來！！`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`AGENT_EXTRA_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`CORRIDOR`,slots:{L:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`......늦었군.`,JPN:`……手遅れか。`,ENG:`I came too late.`,TWN:`……我來晚了。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`그런데 괴물이라니, 대체 뭘 봤길래?`,JPN:`しかし、化け物だなんて、いったい何を見てたんだ？`,ENG:`By the way, didn't he say monster? What did he see?`,TWN:`不過他說怪物，他究竟看到了什麼？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`이 소리는?!`,JPN:`この音は！？`,ENG:`This noise?!`,TWN:`這個聲音是？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`도미닉! 도미닉! 어디에 있나?!`,JPN:`ドミニーク！　ドミニーク！　どこにいる！？`,ENG:`Dominic! Dominic! Where are you?!`,TWN:`多明尼克！多明尼克！你在哪裡？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`아직 살아 있으면 대답해!`,JPN:`まだ生きてるなら答えろ！`,ENG:`Are you still alive? Answer me!`,TWN:`要是還活著就回答我！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`크으윽!!`,JPN:`くううっ！！`,ENG:`Ugh!`,TWN:`咳呃呃！！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`도미닉...... 이런! 몸이 엉망이로군.`,JPN:`ドミニーク……なんてこった！　満身創痍じゃないか。`,ENG:`Dominic? Oh, no! You're in terrible shape!`,TWN:`多明尼克……天哪！你看起來糟透了。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`DOMINIC_DELTA_NULL_NULL`,text:{KOREA:`사, 사령관님? 으윽......`,JPN:`し、司令官？　ううっ……`,ENG:`C-Commander? Argh...`,TWN:`司、司令官？唔……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`DOMINIC_DELTA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`자네를 이런 꼴로 만들 수 있는 상대가 있을 줄은 몰랐는데.`,JPN:`君をこんな目に遭わせる相手がいるとは。`,ENG:`Who did this to you? I didn't know it was even possible.`,TWN:`沒想到還能有把你傷成這樣的傢伙`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`MARIA_DELTA_NULL_NULL`,text:{KOREA:`대체 누구와 싸우고 있던 건가?`,JPN:`いったい何と戦ったんだ？`,ENG:`Who was it?`,TWN:`你到底和誰戰鬥了？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`MARIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`NAYUBIN_SIX_NULL_QM`,text:{KOREA:`이런...... 생각보다 빨리 오셨군요.`,JPN:`おや……思ったよりも到着が早かったですね。`,ENG:`Uh-oh. You came more quickly than I thought.`,TWN:`這……您來得比我想像得還快呢。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}}];export{e as default};